package com.example.logging

import android.app.Application
import android.util.Log
import com.google.gson.Gson
import okhttp3.Interceptor
import okhttp3.Request
import okhttp3.Response
import okio.Buffer
import timber.log.Timber
import java.nio.charset.Charset
import java.util.Locale

private class ReleaseTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        Log.println(priority, tag, message)
        t?.let { Log.println(priority, tag, Log.getStackTraceString(it)) }
        // Optional: forward logs to analytics/monitoring backend here
    }
}

object AppLogger {

    private val json = Gson()

    fun init(app: Application, isDebug: Boolean = BuildConfig.DEBUG) {
        if (isDebug) Timber.plant(Timber.DebugTree()) else Timber.plant(ReleaseTree())
        Timber.i("AppLogger initialized (debug=%s)", isDebug)
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            logException(throwable, "Uncaught exception in thread=${thread.name}")
        }
    }

    /* Authentication */

    fun logAuthSuccess(userId: String) =
        Timber.tag("AUTH").v("SUCCESS user=%s", userId)

    fun logAuthFailure(userId: String?, reason: String?) =
        Timber.tag("AUTH").w("FAILURE user=%s reason=%s", userId ?: "unknown", reason ?: "unknown")

    /* Database */

    fun logDatabaseQuery(sql: String, args: Map<String, Any?>) =
        Timber.tag("DB").v("SQL=%s ARGS=%s", sql, json.toJson(args))

    /* API */

    fun logApiRequest(req: Request, res: Response? = null, elapsedMs: Long? = null) {
        Timber.tag("API").v(
            Locale.US,
            "METHOD=%s URL=%s HEADERS=%s REQ_BODY=%s CODE=%s RES_BODY=%s ELAPSED=%sms",
            req.method,
            req.url,
            json.toJson(req.headers.toMultimap()),
            bodyString(req),
            res?.code ?: "N/A",
            res?.let { bodyString(it) } ?: "N/A",
            elapsedMs ?: -1
        )
    }

    private fun bodyString(req: Request): String = runCatching {
        val copy = req.newBuilder().build()
        val buffer = Buffer()
        copy.body?.writeTo(buffer)
        buffer.readString(Charset.forName("UTF-8"))
    }.getOrElse { "unable to read body: ${it.message}" }

    private fun bodyString(res: Response): String = runCatching {
        res.peekBody(Long.MAX_VALUE).string()
    }.getOrElse { "unable to read body: ${it.message}" }

    /* Exceptions */

    fun logException(t: Throwable, message: String? = null) =
        if (message == null) Timber.tag("EXCEPTION").e(t)
        else Timber.tag("EXCEPTION").e(t, message)
}

/* OkHttp Interceptor for automatic API logging */

class ApiLoggingInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val startNs = System.nanoTime()
        val request = chain.request()
        return try {
            val response = chain.proceed(request)
            val elapsed = (System.nanoTime() - startNs) / 1_000_000
            AppLogger.logApiRequest(request, response, elapsed)
            response
        } catch (e: Exception) {
            AppLogger.logException(e, "Network error url=${request.url}")
            throw e
        }
    }
}

